"use client";

/**
 * WalletBalanceCard — Generado por Concorde
 * Fuente: Figma VOYAGER · "WalletBalanceCard" (nodo 2020:13635)
 *
 * Tarjeta «Billetera» 375×221 (blanca, radius 16, drop shadow suave):
 *   · Header: CardTitle «BILLETERA» (brackets) + ProfileButton «Transacciones ›»
 *   · Divisor #E1E3E2
 *   · Filas SubasCoins / Saldo (label morado + valor morado bold)
 *   · CTA «Adquiere SubasCoins» (Button sm-guest, círculo + texto, centrado)
 */

import type { JSX, MouseEventHandler } from "react";
import CardTitle from "@/concorde/components/CardTitle";
import ProfileButton from "@/concorde/components/ProfileButton";

// ─── Types ────────────────────────────────────────────────────────────────────

export interface WalletBalanceCardProps {
  /** Título de la tarjeta (default "BILLETERA"). */
  title?: string;
  /** Valor de SubasCoins (default ">S< 0"). */
  subasCoins?: string;
  /** Valor de Saldo (default "US$ 0"). */
  saldo?: string;
  /** Acción / enlace del acceso «Transacciones». */
  onTransactions?: MouseEventHandler<HTMLElement>;
  transactionsHref?: string;
  /** Click del CTA «Adquiere SubasCoins». */
  onAcquire?: MouseEventHandler<HTMLButtonElement>;
  className?: string;
}

// ─── Self-contained CSS ───────────────────────────────────────────────────────

const STYLE_ID = "concorde-walletbalancecard-styles";

const STYLES = `
.wbc {
  box-sizing: border-box;
  width: 375px;
  height: 221px;
  border-radius: 16px;
  background: #ffffff;
  box-shadow: 0 0 8px 4px rgba(0,0,0,0.08);
  padding: 16px;
  display: flex;
  flex-direction: column;
  font-family: var(--vmc-font-display, "Plus Jakarta Sans", -apple-system, sans-serif);
}
.wbc__header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 12px;
}
.wbc__divider {
  height: 1px;
  background: #E1E3E2;
  margin-top: 8px;
}
.wbc__body {
  flex: 1;
  display: flex;
  flex-direction: column;
  padding-top: 18px;
}
.wbc__rows {
  display: flex;
  flex-direction: column;
  gap: 12px;
  padding: 0 4px;
}
.wbc__row {
  display: flex;
  align-items: center;
  justify-content: space-between;
}
.wbc__row-label { font-size: 15px; font-weight: 500; color: #3B1782; }
.wbc__row-value { font-size: 15px; font-weight: 700; color: #3B1782; }
.wbc__cta {
  margin-top: auto;
  display: flex;
  justify-content: center;
  padding-bottom: 4px;
}
/* Botón CTA autónomo — mismo look que sm-guest, texto realmente centrado */
.wbc__acquire {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  position: relative;
  width: 250px;
  height: 40px;
  padding: 0 16px;
  border-radius: 9999px;
  border: 2px solid transparent;
  cursor: pointer;
  overflow: hidden;
  font-family: var(--vmc-font-display, "Plus Jakarta Sans", sans-serif);
  font-size: 14px;
  font-weight: 600;
  color: #ffffff;
  text-shadow: rgba(0,0,0,0.2) 0 1px 2px;
  background-image:
    linear-gradient(135deg, #ED8936 0%, #ED8936 40%, #8460e5 100%),
    linear-gradient(135deg, #ffffff 0%, #fbc47d 25%, #ae8eff 75%, #ffffff 100%);
  background-origin: padding-box, border-box;
  background-clip: padding-box, border-box;
  box-shadow: rgba(255,255,255,0.25) 0 1px 0 2px inset, rgba(237,137,54,0.25) 0 2px 6px;
  transition: transform 0.2s cubic-bezier(0.25,0.8,0.25,1), box-shadow 0.25s;
}
.wbc__acquire::before {
  content: "";
  position: absolute;
  inset: 0;
  border-radius: 9999px;
  background: linear-gradient(rgba(255,255,255,0.15) 0%, transparent 55%);
  pointer-events: none;
}
.wbc__acquire-circle {
  position: absolute;
  left: 4px;
  width: 32px;
  height: 32px;
  border-radius: 50%;
  background: rgba(255,255,255,0.2);
}
.wbc__acquire:hover {
  transform: translateY(-1px) scale(1.02);
  box-shadow: rgba(255,255,255,0.2) 0 1px 0 2px inset, rgba(132,96,229,0.3) 0 6px 18px, rgba(237,137,54,0.35) 0 3px 8px;
}
.wbc__acquire:active {
  transform: scale(0.97) translateY(1px);
  box-shadow: rgba(0,0,0,0.22) 0 2px 4px 2px inset;
}
@media (prefers-reduced-motion: reduce) { .wbc__acquire { transition: none; } }
`;

let _stylesInjected = false;

// ─── Component ────────────────────────────────────────────────────────────────

export default function WalletBalanceCard({
  title = "BILLETERA",
  subasCoins = ">S< 0",
  saldo = "US$ 0",
  onTransactions,
  transactionsHref,
  onAcquire,
  className = "",
}: WalletBalanceCardProps): JSX.Element {
  if (typeof document !== "undefined" && !_stylesInjected) {
    if (!document.getElementById(STYLE_ID)) {
      const el = document.createElement("style");
      el.id = STYLE_ID;
      el.textContent = STYLES;
      document.head.appendChild(el);
    }
    _stylesInjected = true;
  }

  return (
    <>
      <style id={`${STYLE_ID}-ssr`} suppressHydrationWarning dangerouslySetInnerHTML={{ __html: STYLES }} />
      <section className={["wbc", className].filter(Boolean).join(" ")} data-component="wallet-balance-card">
        {/* Header: título + acceso a transacciones */}
        <div className="wbc__header">
          <CardTitle title={title} subtitle="" titleSize={14} />
          <ProfileButton href={transactionsHref} onClick={onTransactions} aria-label="Transacciones">
            Transacciones
          </ProfileButton>
        </div>

        <div className="wbc__divider" />

        {/* Cuerpo: SubasCoins / Saldo + CTA */}
        <div className="wbc__body">
          <div className="wbc__rows">
            <div className="wbc__row">
              <span className="wbc__row-label">SubasCoins:</span>
              <span className="wbc__row-value">{subasCoins}</span>
            </div>
            <div className="wbc__row">
              <span className="wbc__row-label">Saldo:</span>
              <span className="wbc__row-value">{saldo}</span>
            </div>
          </div>

          <div className="wbc__cta">
            <button className="wbc__acquire" type="button" onClick={onAcquire}>
              <span className="wbc__acquire-circle" aria-hidden="true" />
              Adquiere SubasCoins
            </button>
          </div>
        </div>
      </section>
    </>
  );
}

"use client";

/**
 * CardTitle — Generado por Concorde
 * Fuente: Figma VOYAGER · "Title" (nodo 2877:280)
 * Sincronizado: 2026-06-12
 *
 * Título de sección con subtítulo y brackets naranjas en esquina
 * superior-izquierda (┌) e inferior-derecha (┘). Estático.
 */

import { useId } from "react";
import type { JSX, ReactNode } from "react";

// ─── Types ────────────────────────────────────────────────────────────────────

export interface CardTitleProps {
  /** Título (default: "SANTANDER CONSUMER"). Acepta texto o nodos (p.ej. un dot + texto). */
  title?: ReactNode;
  /** Subtítulo (default: "10 Ofertas") */
  subtitle?: string;
  /** Tamaño del título en px (default 12 · line-height = size + 4) */
  titleSize?: number;
  /** Tamaño del subtítulo en px (default 14) */
  subtitleSize?: number;
  className?: string;
}

// ─── Self-contained CSS ───────────────────────────────────────────────────────

const STYLE_ID = "concorde-cardtitle-styles";

const CARDTITLE_STYLES = `
.cardtitle {
  position: relative;
  box-sizing: border-box;
  display: inline-flex;
  flex-direction: column;
  padding: 8px 12px;
  font-family: var(--vmc-font-display, "Plus Jakarta Sans", -apple-system, sans-serif);
}
.cardtitle__title {
  margin: 0;
  font-size: 12px;
  font-weight: 600;
  line-height: 16px;
  letter-spacing: 0;
  color: #3b1782;
  white-space: nowrap;
}
.cardtitle__subtitle {
  margin: 2px 0 0;
  font-size: 13px;
  font-weight: 400;
  line-height: 1.2;
  color: #191c1c;
}
.cardtitle__bracket {
  position: absolute;
  pointer-events: none;
}
.cardtitle__bracket--tl { top: 0; left: 0; }
.cardtitle__bracket--br { bottom: 0; right: 0; transform: rotate(180deg); }
`;

let _stylesInjected = false;

// ─── Bracket (┌) — gradiente naranja #FF9639 → #EF852E 40% → #BE3D00 ────────────

function Bracket({ uid, corner }: { uid: string; corner: "tl" | "br" }): JSX.Element {
  return (
    <svg
      className={`cardtitle__bracket cardtitle__bracket--${corner}`}
      width="10"
      height="10"
      viewBox="0 0 10 10"
      fill="none"
      aria-hidden="true"
    >
      <path
        d="M7 1.022H3.769C1.923 1.022 1 1.943 1 3.784V7.007"
        stroke={`url(#${uid}-${corner})`}
        strokeWidth="2"
        strokeLinecap="round"
        strokeLinejoin="round"
      />
      <defs>
        <linearGradient id={`${uid}-${corner}`} x1="4" y1="1.022" x2="4" y2="7.007" gradientUnits="userSpaceOnUse">
          <stop stopColor="#FF9639" /><stop offset="0.4" stopColor="#EF852E" /><stop offset="1" stopColor="#BE3D00" />
        </linearGradient>
      </defs>
    </svg>
  );
}

// ─── Component ────────────────────────────────────────────────────────────────

export default function CardTitle({
  title = "SANTANDER CONSUMER",
  subtitle = "10 Ofertas",
  titleSize = 12,
  subtitleSize = 14,
  className = "",
}: CardTitleProps): JSX.Element {
  const uid = useId().replace(/:/g, "-");

  if (typeof document !== "undefined" && !_stylesInjected) {
    if (!document.getElementById(STYLE_ID)) {
      const el = document.createElement("style");
      el.id = STYLE_ID;
      el.textContent = CARDTITLE_STYLES;
      document.head.appendChild(el);
    }
    _stylesInjected = true;
  }

  return (
    <>
      <style id={`${STYLE_ID}-ssr`} suppressHydrationWarning dangerouslySetInnerHTML={{ __html: CARDTITLE_STYLES }} />
      <div className={["cardtitle", className].filter(Boolean).join(" ")}>
        <Bracket uid={uid} corner="tl" />
        <h3 className="cardtitle__title" style={{ fontSize: titleSize, lineHeight: `${titleSize + 4}px` }}>{title}</h3>
        {subtitle ? <p className="cardtitle__subtitle" style={{ fontSize: subtitleSize }}>{subtitle}</p> : null}
        <Bracket uid={uid} corner="br" />
      </div>
    </>
  );
}

"use client";

/**
 * ProfileButton — Generado por Concorde
 * Fuente: Figma VOYAGER · "ProfileButton" (Status=Default|Hover|Pressed)
 * Nodos: 1274:5029 (default) · 1274:3989 (hover) · 1287:5144 (pressed)
 * Sincronizado: 2026-06-12
 *
 * Botón de navegación a perfil: label morado + círculo con chevron.
 * Figma manda en lo visual (colores/dimensiones); Concorde manda en la interacción
 * (transición de relleno + lift en hover, reduced-motion).
 */

import type { JSX, MouseEventHandler, ReactNode } from "react";

// ─── Types ────────────────────────────────────────────────────────────────────

export interface ProfileButtonProps {
  /** Label (default: "Ir al Perfil") */
  children?: ReactNode;
  /** Si se pasa, renderiza un <a> en vez de <button> */
  href?: string;
  onClick?: MouseEventHandler<HTMLElement>;
  disabled?: boolean;
  className?: string;
  "aria-label"?: string;
}

// ─── Self-contained CSS ───────────────────────────────────────────────────────

const STYLE_ID = "concorde-profilebutton-styles";

const PROFILEBUTTON_STYLES = `
.pprofilebtn {
  display: inline-flex;
  align-items: center;
  gap: 10px;
  padding: 4px;
  background: none;
  border: none;
  cursor: pointer;
  text-decoration: none;
  font-family: var(--vmc-font-display, "Plus Jakarta Sans", -apple-system, sans-serif);
  font-size: 15px;
  font-weight: 600;
  line-height: 20px;
  white-space: nowrap;
  -webkit-tap-highlight-color: transparent;
}

/* Label — default morado #3B1782 (Figma text fill) */
.pprofilebtn__label {
  color: #3b1782;
  transition: color 0.2s ease;
}

/* Círculo 16px con chevron. color = color del chevron (currentColor) */
.pprofilebtn__circle {
  position: relative;
  width: 16px;
  height: 16px;
  flex-shrink: 0;
  border-radius: 9999px;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  background: transparent;
  color: #ef852e;
  transition:
    background 0.2s ease,
    color 0.2s ease,
    box-shadow 0.25s ease,
    transform 0.2s cubic-bezier(0.25, 0.8, 0.25, 1);
}
/* Default: anillo gradiente naranja 1.5px (stroke #FF9C3B → #EF852E 40% → #BE3D00) — mask */
.pprofilebtn__circle::before {
  content: "";
  position: absolute;
  inset: 0;
  border-radius: inherit;
  padding: 1.5px;
  background: linear-gradient(135deg, #ff9c3b 0%, #ef852e 40%, #be3d00 100%);
  -webkit-mask: linear-gradient(#fff 0 0) content-box, linear-gradient(#fff 0 0);
  -webkit-mask-composite: xor;
  mask-composite: exclude;
  pointer-events: none;
  transition: opacity 0.2s ease;
}
.pprofilebtn__chevron {
  position: relative;
  z-index: 1;
  display: block;
}

/* ── Hover: círculo RELLENO naranja + sombra, chevron blanco, lift ── */
.pprofilebtn:hover:not(:disabled) .pprofilebtn__circle {
  background: linear-gradient(90deg, #ff9639 0%, #ef852e 40%, #be3d00 100%);
  color: #ffffff;
  box-shadow: 0 8px 16px rgba(0, 0, 0, 0.1);
  transform: translateY(-1px);
}
.pprofilebtn:hover:not(:disabled) .pprofilebtn__circle::before { opacity: 0; }

/* ── Pressed: texto + chevron gris #99A1AF, círculo naranja oscuro #B25614 → #93420A ── */
.pprofilebtn:active:not(:disabled) .pprofilebtn__label { color: #99a1af; }
.pprofilebtn:active:not(:disabled) .pprofilebtn__circle {
  background: linear-gradient(90deg, #b25614 0%, #93420a 100%);
  color: #99a1af;
  box-shadow: none;
  transform: translateY(0);
}
.pprofilebtn:active:not(:disabled) .pprofilebtn__circle::before { opacity: 0; }

/* ── Focus ── */
.pprofilebtn:focus-visible {
  outline: none;
  border-radius: 8px;
  box-shadow: 0 0 0 2px #ffffff, 0 0 0 4px #8460e5;
}

/* ── Disabled ── */
.pprofilebtn:disabled {
  cursor: not-allowed;
}
.pprofilebtn:disabled .pprofilebtn__label { color: #99a1af; }
.pprofilebtn:disabled .pprofilebtn__circle {
  background: #e1e3e2;
  color: #ffffff;
}
.pprofilebtn:disabled .pprofilebtn__circle::before { opacity: 0; }

/* ── Reduced motion ── */
@media (prefers-reduced-motion: reduce) {
  .pprofilebtn__label,
  .pprofilebtn__circle,
  .pprofilebtn__circle::before { transition: none; }
  .pprofilebtn:hover:not(:disabled) .pprofilebtn__circle { transform: none; }
}
`;

let _stylesInjected = false;

// ─── Chevron (M83 22 L87 19 L83 16 normalizado a viewBox 16×16, centro 8,8) ─────

function Chevron(): JSX.Element {
  return (
    <svg
      className="pprofilebtn__chevron"
      width="16"
      height="16"
      viewBox="0 0 16 16"
      fill="none"
      aria-hidden="true"
    >
      <path d="M6 11L10 8L6 5" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round" />
    </svg>
  );
}

// ─── Component ────────────────────────────────────────────────────────────────

export default function ProfileButton({
  children = "Ir al Perfil",
  href,
  onClick,
  disabled = false,
  className = "",
  "aria-label": ariaLabel,
}: ProfileButtonProps): JSX.Element {
  if (typeof document !== "undefined" && !_stylesInjected) {
    if (!document.getElementById(STYLE_ID)) {
      const el = document.createElement("style");
      el.id = STYLE_ID;
      el.textContent = PROFILEBUTTON_STYLES;
      document.head.appendChild(el);
    }
    _stylesInjected = true;
  }

  const classes = ["pprofilebtn", className].filter(Boolean).join(" ");

  const inner = (
    <>
      <span className="pprofilebtn__label">{children}</span>
      <span className="pprofilebtn__circle" aria-hidden="true">
        <Chevron />
      </span>
    </>
  );

  return (
    <>
      <style id={`${STYLE_ID}-ssr`} suppressHydrationWarning dangerouslySetInnerHTML={{ __html: PROFILEBUTTON_STYLES }} />
      {href && !disabled ? (
        <a className={classes} href={href} onClick={onClick} aria-label={ariaLabel}>
          {inner}
        </a>
      ) : (
        <button type="button" className={classes} onClick={onClick} disabled={disabled} aria-label={ariaLabel}>
          {inner}
        </button>
      )}
    </>
  );
}
